/**
 * Minimal marked.js implementation for Gem Reader.
 * For full feature support (tables, advanced GFM), download the official library:
 * https://cdn.jsdelivr.net/npm/marked/marked.min.js
 */
window.marked = {
    parse: function(text) {
        if (!text) return "";
        return text
            .replace(/^#### (.*$)/gim, '<h3 style="margin:4px 0; color:#333;">$1</h3>')
            .replace(/^### (.*$)/gim, '<h4 style="margin:8px 0; color:#333;">$1</h4>')
            .replace(/^## (.*$)/gim, '<h5 style="margin:10px 0; color:#333;">$1</h5>')
            .replace(/^# (.*$)/gim, '<h6 style="margin:12px 0; color:#333;">$1</h6>')
            .replace(/\*\*(.*?)\*\*/g, '<strong>$1</strong>')
            .replace(/\*(.*?)\*/g, '<em>$1</em>')
            .replace(/^\s*[\-\*]\s+(.*)$/gim, '<div style="display:list-item; list-style-type:disc; margin-left:20px; margin-bottom:4px;">$1</div>')
            .replace(/`(.*?)`/g, '<code style="background:rgba(0,0,0,0.05); padding:2px 4px; border-radius:3px; font-family:monospace;">$1</code>')
            .replace(/\n/g, '<br>');
    }
};